### Implementing a Lexical Command Plugin for Node Insertion in PayloadCMS (TypeScript)

Source: https://github.com/payloadcms/payload/blob/main/docs/rich-text/custom-features.mdx

This TypeScript plugin, `MyNodePlugin`, illustrates how to create a React component that registers a custom Lexical command (`INSERT_MYNODE_COMMAND`). It uses `useLexicalComposerContext` to access the editor instance and `useEffect` to register the command, which inserts a new `MyNode` into the editor upon execution. This pattern allows for custom editor behaviors and content manipulation via Lexical's command system.

```typescript
'use client'\nimport type { LexicalCommand } from '@payloadcms/richtext-lexical/lexical'\n\nimport {\n  createCommand,\n  $getSelection,\n  $isRangeSelection,\n  COMMAND_PRIORITY_EDITOR,\n} from '@payloadcms/richtext-lexical/lexical'\n\nimport { useLexicalComposerContext } from '@payloadcms/richtext-lexical/lexical/react/LexicalComposerContext'\nimport { $insertNodeToNearestRoot } from '@payloadcms/richtext-lexical/lexical/utils'\nimport { useEffect } from 'react'\n\nimport type { PluginComponent } from '@payloadcms/richtext-lexical' // type imports can be imported from @payloadcms/richtext-lexical - even on the client\n\nimport { $createMyNode } from '../nodes/MyNode'\nimport './index.scss'\n\nexport const INSERT_MYNODE_COMMAND: LexicalCommand<void> = createCommand(\n  'INSERT_MYNODE_COMMAND',\n)\n\n/**\n * Plugin which registers a lexical command to\n * insert a new MyNode into the editor\n */\nexport const MyNodePlugin: PluginComponent = () => {\n  // The useLexicalComposerContext hook can be used\n  // to access the lexical editor instance\n  const [editor] = useLexicalComposerContext()\n\n  useEffect(() => {\n    return editor.registerCommand(\n      INSERT_MYNODE_COMMAND,\n      (type) => {\n        const selection = $getSelection()\n\n        if (!$isRangeSelection(selection)) {\n          return false\n        }\n\n        const focusNode = selection.focus.getNode()\n\n        if (focusNode !== null) {\n          const newMyNode = $createMyNode()\n          $insertNodeToNearestRoot(newMyNode)\n        }\n\n        return true\n      },\n      COMMAND_PRIORITY_EDITOR,\n    )\n  }, [editor])\n\n  return null\n}
```

